fix:
private void injectMockCandidate(Class<?> awaitingInjectionClazz, Set<Object> mocks, Object fieldInstance) throws IllegalAccessException {
    for(Field field : orderedInstanceFieldsFrom(awaitingInjectionClazz)) {
        if (isValidType(field)) {
            InjectedValue injected = mockCandidateFilter.filterCandidate(mocks, field, fieldInstance);
            injected.thenInject();
        } else {
            injectNonPrimitiveOrReferenceTypes(mocks, field, fieldInstance);
        }

    }
}

private boolean isValidType(Field field){
   Class<?> cls = field.getType();
    return !cls.isPrimitive() && !cls.equals(String.class);
}

private void injectNonPrimitiveOrReferenceTypes(Set<Object> mocks, Field field, Object instance) throws IllegalArgumentException, IllegalAccessException{
       String rawTypeName = field.toString().split(" ")[1];
       if(rawTypeName.contains("<") ){
           int endIndex = rawTypeName.indexOf('<');
           rawTypeName = rawTypeName.substring(0,endIndex);
       }

      Class <?> typeToCast= null;
        try {
             typeToCast = getUnmockedMatcherByTypeName(mocks ,rawTypeName);

        }catch(ClassNotFoundException e){
            throw new RuntimeException("There was problem during casting process",e);
        } catch(NoSuchBeanDefinitionException e ){
            throw new IllegalArgumentException("You can not create mock for primitive types or classes that do not have public empty constructor", e);
        }

          if(!Modifier.isPublic(typeToCast.getDeclaredConstructor().getModifiers())){
               throw new IllegalArgumentException("You can not create mock for classes that does not have public no arguments constructor"+typeToCast.getName());

           }

           Constructor<?>[] declaredConstructors = typeToCast.getDeclaredConstructors();
           if (declaredConstructors.length > 0) {
               // We find correct constructor
                final ConstraintDesc desc = getApplicableConstructorDescriptor(new MethodDescription(typeToCast), mocks );

                Constructor<?> chosenConstructor = desc.constructor;

                    if (!chosenConstructor.isAccessible()) {
                        chosenConstructor.setAccessible(true);

                    }

                  instance =  chosenConstructor.newInstance();

                   setter(field ,instance ,typeToCast);



           }else {
               setter(field ,instance ,typeToCast);

           }


    }

private void setter(Field field , Object instance ,Class < ? > clazz ) throws IllegalAccessException{

    field.setAccessible(true);

        field.set(clazz.cast(instance));
}

private  Class<?> getUnmockedMatcherByTypeName(Set<Object> mocks , String className) throws ClassNotFoundException, NoSuchBeanDefinitionException {
    String qualifiedName = convertNameToFullyQualifiedName(className);
        Class<?> candidate = Class.forName(qualifiedName);
        if(candidate.isInterface() || alreadyMocksAnyOfTheseClasses(mocks,candidate)){
             throw new NoSuchBeanDefinitionException (" There is already created mock for class" + candidate.getName());

    }
    return candidate;


}
 private boolean alreadyMocksAnyOfTheseClasses(Set<Object> mocks, Class<?> candidate) {
    for (Object mock : mocks) {
        if (mock.getClass().isAssignableFrom(candidate)) {
            return true;
        }
    }
    return false;
}

private String convertNameToFullyQualifiedName(String simpleName) {
    return Thread.currentThread().getContextClassLoader().getPackage().getName()  + '.' + simpleName;
}

